struct Color {
    static const string RED, GREEN, YELLOW, RESET, BOLD;
};
const string Color::RED="\033[31m", Color::GREEN="\033[32m", Color::YELLOW="\033[33m", Color::RESET="\033[0m", Color::BOLD="\033[1m";

struct TestCase {
    int n; vector<vector<int>> edges; int k;
    int expected;
};

template<typename T>
string formatValue(const T& v) {
    stringstream ss; ss << v; return ss.str();
}

template<typename T>
string formatValue(const bool& v) {
    return v ? "true" : "false";
}

template<typename T>
string formatValue(const vector<T>& v) {
    string s = "[";
    for(size_t i=0; i<v.size(); ++i) s += formatValue(v[i]) + (i==v.size()-1 ? "" : ", ");
    return s + "]";
}

bool compare(const vector<int>& a, const vector<int>& b) { return a == b; }
bool compare(int a, int b) { return a == b; }
bool compare(bool a, bool b) { return a == b; }

